INSERT INTO `v1_0042bd9345e8b27b53dab5be0038aedea07f6df862fc099d2b181abb1e24937c` VALUES (1, 11, 6, 113511, 0, 0, "あなた様のため…必ずや\n忘れられない最高の夏休みを\nお贈りいたしますわ…", 1007001, 1007001042, 0, 0);
