INSERT INTO `v1_0042bd9345e8b27b53dab5be0038aedea07f6df862fc099d2b181abb1e24937c` VALUES (1, 11, 6, 113511, 0, 0, "はて…？　私は来年の夏も\n一緒に過ごすので思い出して\nいただく必要はないのですが…", 1007001, 1007001052, 0, 0);
