INSERT INTO `v1_0042bd9345e8b27b53dab5be0038aedea07f6df862fc099d2b181abb1e24937c` VALUES (1, 11, 5, 113511, 0, 0, "静かな島で弟くんと暮らす…\nここは本当に天国だね。", 1007005, 1007005040, 0, 0);
