INSERT INTO `v1_0042bd9345e8b27b53dab5be0038aedea07f6df862fc099d2b181abb1e24937c` VALUES (1, 11, 6, 113411, 0, 0, "これを幸せと呼ばずして\n何を幸せと呼べば\nよいのでしょう…", 1007005, 1007005045, 0, 0);
