INSERT INTO `v1_0042bd9345e8b27b53dab5be0038aedea07f6df862fc099d2b181abb1e24937c` VALUES (1, 11, 6, 113411, 0, 0, "そもそも、あなた様からの\nボールを落とすなんて、絶対に\nあってはいけませんわ…", 1007007, 1007007028, 0, 0);
