INSERT INTO `v1_0042bd9345e8b27b53dab5be0038aedea07f6df862fc099d2b181abb1e24937c` VALUES (1, 11, 6, 113511, 0, 0, "その通り！\nどんな場所に来ようと\n必ず打ち返してみせるよ！", 1007007, 1007007033, 0, 0);
